import{_ as e,c as p,o as t,ae as r}from"./chunks/framework.BvcDoAct.js";const S=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"zh-cn/Management2/PART2/2.md","filePath":"zh-cn/Management2/PART2/2.md"}'),n={name:"zh-cn/Management2/PART2/2.md"};function o(s,a,i,h,l,c){return t(),p("div",null,[...a[0]||(a[0]=[r('<p>►2022/12</p><h2 id="通过商业媒体采访所感受到的自信与笃定" tabindex="-1">通过商业媒体采访所感受到的自信与笃定 <a class="header-anchor" href="#通过商业媒体采访所感受到的自信与笃定" aria-label="Permalink to &quot;通过商业媒体采访所感受到的自信与笃定&quot;">​</a></h2><p>#领导力 #变革 #自信 #笃定</p><h3 id="正因为日本经济和音乐行业已经衰弱到需要-救世主-反而在结果上推动了bmsg" tabindex="-1">“正因为日本经济和音乐行业已经衰弱到需要‘救世主’，反而在结果上推动了BMSG” <a class="header-anchor" href="#正因为日本经济和音乐行业已经衰弱到需要-救世主-反而在结果上推动了bmsg" aria-label="Permalink to &quot;“正因为日本经济和音乐行业已经衰弱到需要‘救世主’，反而在结果上推动了BMSG”&quot;">​</a></h3><p><strong>2023年终于拉开帷幕。新的一年，对BMSG以及SKY-HI来说会是怎样的一年呢？从1月13日起，围绕BMSG全新男子组合“MAZZEL”诞生过程的选秀纪录节目《MISSIONx2》将在YouTube上线，今年春天MAZZEL也将正式出道。旗下艺人的各类挑战也会更加积极推进。</strong></p><p><strong>无论是在选秀《THE FIRST》中引导参与者的方式、在节目中反复强调的理念，还是将由此出道的BE:FIRST培养成当红艺人的能力，SKY-HI如今都备受关注。作为率领势头最猛的管理厂牌BMSG的负责人，尤其是在过去一年里，他被商业媒体以“新时代领导者”“音乐行业的革新者”等标签频繁采访。通过这些不同于以往“艺人视角”的采访，他也产生了不少新的感受。</strong></p><p>像《日经娱乐》这种媒体，可能因为从《THE FIRST》最初阶段就开始关注我们，所以情况略有不同。但我在接受商业媒体采访时强烈感受到的一点是，他们一直在寻找“新时代的领导者”和“新时代的管理方式”。</p><p>不仅仅是娱乐行业，在政治、经济、体育等各个领域，社会始终在寻找“救世主”。如果用足球来比喻，为了回应这种期待，我觉得成功的关键在于——“跑到能接到好传球的位置”。</p><p>但如果只是盲目地朝球门冲，防守球员也会跟上来，好的传球也不会出现。所以你需要成为那种能够凭借感觉和经验，跑到最佳位置的人；只要做到了这一点，球自然就会传到你脚下。</p><p>反过来说，如果给你传球的人消失了、转会了——换句话说，环境一变你就无法发挥，那就是很严重的问题。所以我强烈觉得，最终必须成为那种可以自己组织比赛、提升团队士气，甚至就算不上场也能通过理念让团队赢球的人。</p><p>我多少感觉到，社会正在寻找新时代领导者或“救世主”这件事，和我现在的行动产生了某种共振，而且我也觉得必须让这种趋势进一步加速。</p><h3 id="从反响中获得的-自信-与-笃定" tabindex="-1">从反响中获得的“自信”与“笃定” <a class="header-anchor" href="#从反响中获得的-自信-与-笃定" aria-label="Permalink to &quot;从反响中获得的“自信”与“笃定”&quot;">​</a></h3><p>还有一点让我惊讶的是，通过商业媒体采访我才发现，音乐行业所谓的“常识”，其实外界几乎并不了解。</p><p>虽然我是活在艺人这种多少有些脱离现实的世界里的人，但我同时也是普通社会的一员，所以一直以来，我都觉得艺人和偶像行业的运行方式以及商业模式存在不合理之处。但业内的人却把这些当作理所当然，甚至很多粉丝似乎也并不会对此产生违和感，这让我一直觉得很不可思议。</p><p>当我向商业媒体的人解释“艺人和偶像行业其实是这样运作的”——哪怕只是讲述过去二十年来的行业常识——他们都会感到震惊。甚至只要表达出“我对这些问题有意识”，就足以形成一篇完整的报道，而且往往还能成为当周阅读量第一的文章，获得大量共鸣与反馈。</p><p>但这些想法其实从创业初期就已经存在了。它们能获得如此反响，一方面让我在“社会人意识”上有所成长，也让我更清晰地认识到自身的优势。</p><p>同时，这也让我更加确信，自己正在做的事、以及打算去做的事，并没有错；也让我再次强烈感受到行业的危机感。某种意义上来说，正因为日本经济和音乐行业已经衰弱到需要“救世主”，反而在结果上推动了BMSG的发展。</p><p>我现在也算是终于迈入了一个新的阶段——必须以“经营者”的身份去对外展示公司。</p><h3 id="作为-新时代领导者-被推上神坛的觉悟" tabindex="-1">作为“新时代领导者”被推上神坛的觉悟 <a class="header-anchor" href="#作为-新时代领导者-被推上神坛的觉悟" aria-label="Permalink to &quot;作为“新时代领导者”被推上神坛的觉悟&quot;">​</a></h3><p><strong>当被问到，对于媒体将其作为“新时代领导者”推到台前，是否会感到困惑时，他回答说：“或许这种觉悟，也是最近才真正建立起来的。”</strong></p><p>要实现我在创立BMSG时提出的愿景，仅仅“让艺人走红”是不够的，还必须让“BMSG本身具备影响力”。商业媒体采访所带来的传播，也正是在帮助实现这一点。</p><p>因此，我认为自己必须带着觉悟，登上被抬起的那顶“神轿”。站在上面当然有掉下来的风险，也意味着当有人投石时，你会是最显眼的那个，所以确实会感到害怕。</p><p>但我绝对不能让BE:FIRST站到那个位置上。一旦发生什么事情，就算责任在他们身上，我也无法面对他们。</p><p>我其实并不喜欢“保护艺人”这种说法，甚至对这个表达有些违和感。但为了实现我所期望的——“让艺人实现身心健康的成长”，在接下来的几年里，我必须拼尽全力站在最前面，这是我非常明确的觉悟。</p><p>现在，当初创业时所说的一切，正在一点一点显现出来，我能强烈感受到一种“势能”。比如，作为艺人自由活动时所面临的障碍开始浮出水面；像BE:FIRST与INI这样的艺人之间合作变得越来越多；红白歌会、唱片大奖等节目的出演阵容也在发生变化。</p><p>过去那些被当作“潜规则”的所谓“名额”，正在逐渐瓦解。我清晰地感受到，整个娱乐行业正在发生改变，而且今后长期存在的问题会进一步浮现出来。这正是我所说的“势能”。</p><p>“势能”这个词，是我在读了Twitter连载漫画《100话让创业公司崩溃》之后开始喜欢用的。现在也终于有了那种可以单纯享受这些词语的心态了（笑）。</p><h3 id="数不清的-高光时刻" tabindex="-1">数不清的“高光时刻” <a class="header-anchor" href="#数不清的-高光时刻" aria-label="Permalink to &quot;数不清的“高光时刻”&quot;">​</a></h3><p><strong>在这条没有既定道路、却以惊人速度前进的过程中，他笑着说，作为领队的孤独“现在连感受的时间都没有”。最后，我们问他：自BMSG成立以来，最幸福的瞬间是什么？</strong></p><p>“哇，这可太多了。现在BE:FIRST巡演的每一场我都会有这种感觉，MAZZEL排练的时候也经常会有，（练习生）RUI和TAIKI去迪士尼乐园发来照片的时候我也觉得很幸福。</p><p>还有，2021年12月12日我生日那天，工作人员和旗下艺人一起给我做了一个非常用心的生日祝福视频，那一刻的幸福感我到现在都记得很清楚。刚好那之前的11月是公司最困难的时候之一，也是经历了低谷之后的阶段。</p><p>幸福的瞬间，真要说的话根本数不完（笑）。真的，多到不行！”</p>',32)])])}const _=e(n,[["render",o]]);export{S as __pageData,_ as default};
